mapper.select:
select date_format(r.biz_date, '%Y-%m-%d') as bizDate, r.streamer_id as streamerId, s.stage_name as stageName, sum(r.total_xu) as totalXu from live_daily_report r inner join live_streamer s on s.streamer_id = r.streamer_id where s.status = '0' and r.biz_date between #{beginDate} and #{endDate}
and r.streamer_id = #{streamerId}
group by r.biz_date, r.streamer_id, s.stage_name order by r.biz_date, r.streamer_id

select c.customer_id as customerId,
       c.nickname,
       c.badge,
       ft.first_gift_date as firstTipDate,
       sum(case when gr.biz_date = ft.first_gift_date then gr.xu else 0 end) as totalXu
from (
    select streamer_id, customer_id, min(biz_date) as first_gift_date
    from live_gift_record
    where streamer_id = #{streamerId}
    group by streamer_id, customer_id
) ft
join live_gift_record gr on gr.streamer_id = ft.streamer_id and gr.customer_id = ft.customer_id
join live_customer c on c.customer_id = ft.customer_id and c.streamer_id = ft.streamer_id
where ft.first_gift_date between #{beginDate} and #{endDate}
  and gr.biz_date between #{beginDate} and #{endDate}
  and ft.streamer_id = #{streamerId}
  and c.merged_into_id is null
group by c.customer_id, c.nickname, c.badge, ft.first_gift_date
order by totalXu desc

select cc.biz_date as bizDate, c.nickname
from live_chat_contact cc
join live_customer c on c.customer_id = cc.customer_id
where cc.streamer_id = #{streamerId}
order by cc.biz_date desc
limit #{limit}

select gr.biz_date as bizDate, c.nickname, gr.xu
from live_gift_record gr
join live_customer c on c.customer_id = gr.customer_id
where gr.streamer_id = #{streamerId}
order by gr.biz_date desc, gr.xu desc
limit #{limit}

select c.customer_id as customerId, c.nickname, c.badge, c.streamer_id as streamerId, s.stage_name as stageName, d.biz_date as bizDate, coalesce(g.giftXu, 0) as giftXu, coalesce(ch.hasInteraction, 0) as hasInteraction, coalesce(ch.hasContact, 0) as hasContact, coalesce(fr.hasPendingFollow, 0) as hasPendingFollow, coalesce(t.totalXu, 0) as totalXu from ( select streamer_id, customer_id, biz_date from live_gift_record where biz_date between #{beginDate} and #{endDate} union select streamer_id, customer_id, biz_date from live_chat_contact where biz_date between #{beginDate} and #{endDate} ) d join live_customer c on c.customer_id = d.customer_id and c.streamer_id = d.streamer_id join live_streamer s on s.streamer_id = d.streamer_id left join ( select streamer_id, customer_id, biz_date, sum(xu) as giftXu from live_gift_record where biz_date between #{beginDate} and #{endDate} group by streamer_id, customer_id, biz_date ) g on g.streamer_id = d.streamer_id and g.customer_id = d.customer_id and g.biz_date = d.biz_date left join ( select streamer_id, customer_id, biz_date, max(has_interaction) as hasInteraction, 1 as hasContact from live_chat_contact where biz_date between #{beginDate} and #{endDate} group by streamer_id, customer_id, biz_date ) ch on ch.streamer_id = d.streamer_id and ch.customer_id = d.customer_id and ch.biz_date = d.biz_date left join ( select streamer_id, customer_id, biz_date, 1 as hasPendingFollow from live_follow_record where biz_date between #{beginDate} and #{endDate} and follow_status = 'pending' ) fr on fr.streamer_id = d.streamer_id and fr.customer_id = d.customer_id and fr.biz_date = d.biz_date left join ( select streamer_id, customer_id, sum(xu) as totalXu from live_gift_record where biz_date between #{beginDate} and #{endDate} group by streamer_id, customer_id ) t on t.streamer_id = d.streamer_id and t.customer_id = d.customer_id where c.merged_into_id is null and s.status = '0'
and d.streamer_id = #{streamerId}
order by totalXu desc, c.nickname, d.biz_date
